# Helper function to perform single LU solve
@triton.jit
def _solve_single_lu(A, Bs, out, pivot=True):
    n = A.shape[0]
    k = Bs.shape[1]

    # Allocate temporary storage
    L = tl.zeros((n, n), dtype=tl.float32)
    U = tl.zeros((n, n), dtype=tl.float32)

    # Copy A to U
    for i in range(n):
        for j in range(n):
            U[i, j] = A[i, j]

    # Perform LU decomposition
    if pivot:
        # Simple pivot implementation
        for i in range(n):
            # Find pivot
            max_idx = i
            max_val = abs(U[i, i])
            for j in range(i+1, n):
                if abs(U[j, i]) > max_val:
                    max_idx = j
                    max_val = abs(U[j, i])

            # Swap rows if needed
            if max_idx != i:
                for j in range(n):
                    temp = U[i, j]
                    U[i, j] = U[max_idx, j]
                    U[max_idx, j] = temp

            # Forward elimination
            for j in range(i+1, n):
                factor = U[j, i] / U[i, i]
                for l in range(i, n):
                    U[j, l] -= factor * U[i, l]

            # Store L matrix
            L[i, i] = 1.0
            for j in range(i):
                L[i, j] = U[i, j]
                U[i, j] = 0.0
    else:
        # Non-pivoted LU decomposition
        for i in range(n):
            # Forward elimination
            for j in range(i+1, n):
                factor = U[j, i] / U[i, i]
                for l in range(i, n):
                    U[j, l] -= factor * U[i, l]

            # Store L matrix
            L[i, i] = 1.0
            for j in range(i):
                L[i, j] = U[i, j]
                U[i, j] = 0.0

    # Solve Ly = B
    y = tl.zeros((n, k), dtype=tl.float32)
    for i in range(n):
        for j in range(k):
            y[i, j] = Bs[i, j]

    for i in range(n):
        for j in range(i):
            for l in range(k):
                y[i, l] -= L[i, j] * y[j, l]

    # Solve Ux = y
    for i in range(n-1, -1, -1):
        for l in range(k):
            for j in range(i+1, n):
                y[i, l] -= U[i, j] * y[j, l]
            y[i, l] /= U[i, i]

    # Store result
    for i in range(n):
        for j in range(k):
            out[i, j] = y[i, j]
